class Solution:
    def countCompleteSubstrings(self, word: str, k: int) -> int:
        n = len(word)
        res = 0
        i = 0

        while i < n:
            j = i
            # Check for adjacent characters with difference > 2
            while j + 1 < n and abs(ord(word[j + 1]) - ord(word[j])) <= 2:
                j += 1

            # Now, check all substrings in word[i...j] for the complete condition
            for l in range(i, j + 1):
                for r in range(l, j + 1):
                    substr = word[l:r + 1]
                    freq = {}
                    for ch in substr:
                        freq[ch] = freq.get(ch, 0) + 1
                    valid = True
                    for count in freq.values():
                        if count != k:
                            valid = False
                            break
                    if valid:
                        res += 1
            i = j + 1

        return res
